import{c as t,Q as i,j as a,m as n}from"./chunks/framework.BXc4yaFE.js";const h=JSON.parse('{"title":"Retrieval-Augmented Generation for Large Language Models: A Survey","description":"","frontmatter":{"title":"Retrieval-Augmented Generation for Large Language Models: A Survey","arxiv_id":2312.10997,"authors":"Yunfan Gao, Yun Xiong, Xinyu Gao, Kangxiang Jia, Jinliu Pan, Yuxi Bi, Yi Dai, Jiawei Sun, Meng Wang, Haofen Wang","fetched":"2026-05-26T00:00:00.000Z","published":"2023-12-18T00:00:00.000Z","source":"https://arxiv.org/abs/2312.10997","source_tier":"P"},"headers":[],"relativePath":"research/papers/2023-12-18-retrieval-augmented-generation-survey-2312-10997.md","filePath":"research/papers/2023-12-18-retrieval-augmented-generation-survey-2312-10997.md","lastUpdated":1779901665000}'),r={name:"research/papers/2023-12-18-retrieval-augmented-generation-survey-2312-10997.md"};function o(s,e,l,d,u,c){return i(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="retrieval-augmented-generation-for-large-language-models-a-survey" tabindex="-1">Retrieval-Augmented Generation for Large Language Models: A Survey <a class="header-anchor" href="#retrieval-augmented-generation-for-large-language-models-a-survey" aria-label="Permalink to &quot;Retrieval-Augmented Generation for Large Language Models: A Survey&quot;">​</a></h1><p><strong>Authors</strong>: Yunfan Gao, Yun Xiong, Xinyu Gao, Kangxiang Jia, Jinliu Pan, Yuxi Bi, Yi Dai, Jiawei Sun, Meng Wang, Haofen Wang <strong>Published</strong>: December 2023 <strong>Source</strong>: <a href="https://arxiv.org/abs/2312.10997" target="_blank" rel="noreferrer">https://arxiv.org/abs/2312.10997</a><strong>arXiv ID</strong>: 2312.10997 <strong>Categories</strong>: cs.CL (Computation and Language); cs.AI (Artificial Intelligence)</p><hr><h2 id="abstract" tabindex="-1">Abstract <a class="header-anchor" href="#abstract" aria-label="Permalink to &quot;Abstract&quot;">​</a></h2><p>Large Language Models (LLMs) showcase impressive capabilities but encounter challenges like hallucination, outdated knowledge, and non-transparent, untraceable reasoning processes. Retrieval-Augmented Generation (RAG) has emerged as a promising solution by incorporating knowledge from external databases. This enhances the accuracy and credibility of the generation, particularly for knowledge-intensive tasks, and allows for continuous knowledge updates and integration of domain-specific information. RAG synergistically merges LLMs&#39; intrinsic knowledge with the vast, dynamic repositories of external databases. This comprehensive review paper offers a detailed examination of the progression of RAG paradigms, encompassing the Naive RAG, the Advanced RAG, and the Modular RAG. It meticulously scrutinizes the tripartite foundation of RAG frameworks, which includes the retrieval, the generation and the augmentation techniques. The paper highlights the state-of-the-art technologies embedded in each of these critical components, providing a profound understanding of the advancements in RAG systems. Furthermore, this paper introduces up-to-date evaluation framework and benchmark. At the end, this article delineates the challenges currently faced and points out prospective avenues for research and development.</p><p><strong>Index Terms</strong>: Large language model, retrieval-augmented generation, natural language processing, information retrieval</p><hr><h2 id="core-thesis" tabindex="-1">Core Thesis <a class="header-anchor" href="#core-thesis" aria-label="Permalink to &quot;Core Thesis&quot;">​</a></h2><p>RAG is the most practical solution for grounding LLMs in current, verifiable knowledge without the cost of retraining. The paper organizes the field around three evolutionary paradigms (Naive → Advanced → Modular RAG), dissects retrieval/generation/augmentation as the tripartite technical foundation, and proposes a standardized evaluation framework covering 26 tasks and ~50 datasets.</p><hr><h2 id="i-introduction" tabindex="-1">I. Introduction <a class="header-anchor" href="#i-introduction" aria-label="Permalink to &quot;I. Introduction&quot;">​</a></h2><p>Large language models (LLMs) have achieved remarkable success, though they still face significant limitations, especially in domain-specific or knowledge-intensive tasks, notably producing &quot;hallucinations&quot; when handling queries beyond their training data or requiring current information. To overcome challenges, Retrieval-Augmented Generation (RAG) enhances LLMs by retrieving relevant document chunks from external knowledge base through semantic similarity calculation. By referencing external knowledge, RAG effectively reduces the problem of generating factually incorrect content.</p><p>RAG technology has rapidly developed in recent years. The development trajectory of RAG in the era of large models exhibits several distinct stage characteristics:</p><ol><li><strong>Pre-ChatGPT era</strong>: RAG&#39;s inception coincided with the rise of the Transformer architecture, focusing on enhancing language models by incorporating additional knowledge through Pre-Training Models (PTM).</li><li><strong>Post-ChatGPT era</strong>: RAG research shifted towards providing better information for LLMs to answer more complex and knowledge-intensive tasks during the inference stage.</li><li><strong>Fine-tuning integration</strong>: Enhancement of RAG began to incorporate more with LLM fine-tuning techniques.</li></ol><p><strong>Contributions of this paper</strong>:</p><ul><li>Thorough and systematic review of state-of-the-art RAG methods, delineating evolution through Naive RAG, Advanced RAG, and Modular RAG paradigms.</li><li>Identification and discussion of central technologies integral to the RAG process: &quot;Retrieval&quot;, &quot;Generation&quot; and &quot;Augmentation&quot;.</li><li>Summary of current assessment methods covering 26 tasks, nearly 50 datasets, outlining evaluation objectives and metrics, as well as benchmarks and tools.</li></ul><hr><h2 id="ii-overview-of-rag" tabindex="-1">II. Overview of RAG <a class="header-anchor" href="#ii-overview-of-rag" aria-label="Permalink to &quot;II. Overview of RAG&quot;">​</a></h2><p>A typical RAG application consists of 3 steps:</p><ol><li><strong>Indexing</strong>: Documents are split into chunks, encoded into vectors, and stored in a vector database.</li><li><strong>Retrieval</strong>: Retrieve the Top-k chunks most relevant to the question based on semantic similarity.</li><li><strong>Generation</strong>: Input the original question and the retrieved chunks together into LLM to generate the final answer.</li></ol><h3 id="ii-a-naive-rag" tabindex="-1">II-A. Naive RAG <a class="header-anchor" href="#ii-a-naive-rag" aria-label="Permalink to &quot;II-A. Naive RAG&quot;">​</a></h3><p>The Naive RAG follows a traditional &quot;Retrieve-Read&quot; framework:</p><ul><li><strong>Indexing</strong>: Raw data (PDF, HTML, Word, Markdown) is cleaned, converted to plain text, segmented into chunks, encoded into vector representations, and stored in a vector database.</li><li><strong>Retrieval</strong>: The query is transformed into a vector; top-K most similar chunks are retrieved.</li><li><strong>Generation</strong>: Query and selected documents are synthesized into a coherent prompt for the LLM.</li></ul><p><strong>Drawbacks of Naive RAG</strong>:</p><ul><li><em>Retrieval Challenges</em>: Struggles with precision and recall, leading to misaligned or irrelevant chunks and missing crucial information.</li><li><em>Generation Difficulties</em>: Hallucination, irrelevance, toxicity, or bias in outputs.</li><li><em>Augmentation Hurdles</em>: Disjointed outputs, redundancy from multiple sources, over-reliance on augmented information.</li></ul><h3 id="ii-b-advanced-rag" tabindex="-1">II-B. Advanced RAG <a class="header-anchor" href="#ii-b-advanced-rag" aria-label="Permalink to &quot;II-B. Advanced RAG&quot;">​</a></h3><p>Advanced RAG introduces improvements to overcome Naive RAG limitations, focusing on retrieval quality via pre-retrieval and post-retrieval strategies.</p><p><strong>Pre-retrieval process</strong>:</p><ul><li>Optimizing indexing: enhancing data granularity, optimizing index structures, adding metadata, alignment optimization, mixed retrieval.</li><li>Query optimization: query rewriting, query transformation, query expansion.</li></ul><p><strong>Post-retrieval process</strong>:</p><ul><li>Re-ranking retrieved information to relocate most relevant content to the edges of the prompt.</li><li>Context compression to mitigate information overload and dilution of key details.</li></ul><h3 id="ii-c-modular-rag" tabindex="-1">II-C. Modular RAG <a class="header-anchor" href="#ii-c-modular-rag" aria-label="Permalink to &quot;II-C. Modular RAG&quot;">​</a></h3><p>Modular RAG advances beyond the former two paradigms, offering enhanced adaptability and versatility. It incorporates diverse strategies for improving components, supports both sequential processing and integrated end-to-end training.</p><p><strong>New Modules</strong>:</p><ul><li><em>Search module</em>: Direct searches across various data sources (search engines, databases, knowledge graphs) using LLM-generated code and query languages.</li><li><em>RAG-Fusion</em>: Multi-query strategy expanding user queries into diverse perspectives, with parallel vector searches and intelligent re-ranking.</li><li><em>Memory module</em>: Leverages LLM&#39;s memory to guide retrieval, creating an unbounded memory pool via iterative self-enhancement.</li><li><em>Routing</em>: Navigates through diverse data sources, selecting the optimal pathway.</li><li><em>Predict module</em>: Reduces redundancy and noise by generating context directly through the LLM.</li><li><em>Task Adapter</em>: Tailors RAG to various downstream tasks, automating prompt retrieval for zero-shot inputs.</li></ul><p><strong>New Patterns</strong>:</p><ul><li>Rewrite-Retrieve-Read: LLM refines retrieval queries through a rewriting module.</li><li>Generate-Read: Replaces traditional retrieval with LLM-generated content.</li><li>Recite-Read: Emphasizes retrieval from model weights.</li><li>Demonstrate-Search-Predict (DSP): Dynamic use of module outputs to bolster another module&#39;s functionality.</li><li>ITER-RETGEN: Iterative Retrieve-Read-Retrieve-Read flow.</li><li>FLARE and Self-RAG: Adaptive retrieval evaluating necessity of retrieval based on different scenarios.</li></ul><h3 id="ii-d-rag-vs-fine-tuning" tabindex="-1">II-D. RAG vs. Fine-Tuning <a class="header-anchor" href="#ii-d-rag-vs-fine-tuning" aria-label="Permalink to &quot;II-D. RAG vs. Fine-Tuning&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Dimension</th><th>Prompt Engineering</th><th>RAG</th><th>Fine-Tuning</th></tr></thead><tbody><tr><td>External Knowledge</td><td>Low</td><td>High</td><td>Low–Medium</td></tr><tr><td>Model Adaptation</td><td>Low</td><td>Low–Medium</td><td>High</td></tr><tr><td>Knowledge Updates</td><td>Static</td><td>Real-time</td><td>Requires retraining</td></tr><tr><td>Interpretability</td><td>High</td><td>High</td><td>Low</td></tr><tr><td>Hallucination Reduction</td><td>Limited</td><td>Strong</td><td>Moderate</td></tr><tr><td>Latency</td><td>Low</td><td>Higher</td><td>Low (after training)</td></tr></tbody></table><p>Key finding: RAG consistently outperforms unsupervised fine-tuning for both existing knowledge encountered during training and entirely new knowledge. RAG and FT are complementary and can be combined for optimal performance.</p><hr><h2 id="iii-retrieval" tabindex="-1">III. Retrieval <a class="header-anchor" href="#iii-retrieval" aria-label="Permalink to &quot;III. Retrieval&quot;">​</a></h2><h3 id="iii-a-retrieval-source" tabindex="-1">III-A. Retrieval Source <a class="header-anchor" href="#iii-a-retrieval-source" aria-label="Permalink to &quot;III-A. Retrieval Source&quot;">​</a></h3><p><strong>Data Structures</strong>:</p><ul><li><em>Unstructured Data</em> (text): Most widely used; primary sources include Wikipedia Dumps (HotpotQA, DPR), cross-lingual text, and domain-specific data (medical, legal).</li><li><em>Semi-structured data</em> (PDF): Challenges include text splitting separating tables and complications for semantic similarity searches. Approaches: Text-2-SQL queries via LLM code capabilities, or transforming tables to text.</li><li><em>Structured data</em> (Knowledge Graphs): More precise, verified information. KnowledGPT generates KB search queries. G-Retriever integrates GNNs + LLMs + RAG with PCST optimization for targeted graph retrieval.</li><li><em>LLMs-Generated Content</em>: SKR classifies questions as known/unknown and applies retrieval selectively. GenRead replaces the retriever with an LLM generator. Selfmem iteratively creates an unbounded memory pool.</li></ul><p><strong>Retrieval Granularity</strong> (fine to coarse): Token → Phrase → Sentence → Proposition → Chunks → Document. DenseX proposed propositions as retrieval units—atomic expressions encapsulating unique factual segments in concise, self-contained format. For KGs: Entity → Triplet → Sub-Graph.</p><h3 id="iii-b-indexing-optimization" tabindex="-1">III-B. Indexing Optimization <a class="header-anchor" href="#iii-b-indexing-optimization" aria-label="Permalink to &quot;III-B. Indexing Optimization&quot;">​</a></h3><p><strong>Chunking Strategy</strong>:</p><ul><li>Fixed token splits (100/256/512 tokens): Larger chunks = more context + more noise; smaller chunks = less noise + incomplete context.</li><li>Recursive splits and sliding window methods for layered retrieval.</li><li>Small2Big: sentences as retrieval unit, surrounding sentences provided as context to LLMs.</li></ul><p><strong>Metadata Attachments</strong>:</p><ul><li>Enrich chunks with page number, file name, author, category, timestamp.</li><li>Time-aware RAG through timestamp weighting for knowledge freshness.</li><li>Artificially constructed metadata: paragraph summaries, hypothetical questions (Reverse HyDE).</li></ul><p><strong>Structural Index</strong>:</p><ul><li><em>Hierarchical index</em>: Parent-child file relationships with data summaries at each node for swift traversal.</li><li><em>Knowledge Graph index</em>: Maintains consistency, delineates connections between concepts/entities. KGP builds inter-document KG index with nodes (paragraphs/structures) and edges (semantic/lexical similarity or structural relationships).</li></ul><h3 id="iii-c-query-optimization" tabindex="-1">III-C. Query Optimization <a class="header-anchor" href="#iii-c-query-optimization" aria-label="Permalink to &quot;III-C. Query Optimization&quot;">​</a></h3><p><strong>Query Expansion</strong>:</p><ul><li><em>Multi-Query</em>: Prompt engineering to expand queries via LLMs, executed in parallel.</li><li><em>Sub-Query</em>: Decompose complex questions into simpler sub-questions using least-to-most prompting.</li><li><em>Chain-of-Verification (CoVe)</em>: Expanded queries validated by LLM to reduce hallucinations.</li></ul><p><strong>Query Transformation</strong>:</p><ul><li><em>Query Rewrite</em>: Prompt LLM to rewrite queries; specialized smaller models (RRR). Taobao&#39;s BEQUE enhanced recall for long-tail queries.</li><li><em>HyDE</em>: Construct hypothetical documents (assumed answers) to focus on answer-to-answer embedding similarity.</li><li><em>Step-back Prompting</em>: Abstract original query to generate high-level concept question; use both step-back and original queries for retrieval.</li></ul><p><strong>Query Routing</strong>:</p><ul><li><em>Metadata Router/Filter</em>: Extract keywords from query, filter based on keywords and chunk metadata.</li><li><em>Semantic Router</em>: Route based on semantic similarity of query to routing options.</li></ul><hr><h2 id="iv-generation" tabindex="-1">IV. Generation <a class="header-anchor" href="#iv-generation" aria-label="Permalink to &quot;IV. Generation&quot;">​</a></h2><h3 id="iv-a-post-retrieval-process" tabindex="-1">IV-A. Post-Retrieval Process <a class="header-anchor" href="#iv-a-post-retrieval-process" aria-label="Permalink to &quot;IV-A. Post-Retrieval Process&quot;">​</a></h3><p>Key challenge: integrating retrieved context effectively with the query without overwhelming the LLM.</p><p><strong>Reranking</strong>: Reorder retrieved documents to prioritize the most relevant. Methods include rule-based (diversity, recency), model-based (BERT-series cross-encoders), and LLM-based reranking. Addresses the &quot;lost in the middle&quot; problem where LLMs focus on beginning/end of context.</p><p><strong>Context Selection/Compression</strong>: Reduce irrelevant information in retrieved documents. Methods include:</p><ul><li>Token-level filtering (remove less informative tokens)</li><li>Sentence-level compression (select most relevant sentences)</li><li>Training dedicated compressor models (RECOMP: extractive or abstractive compression)</li><li>Information Extraction (IE)-based approaches</li></ul><h3 id="iv-b-llm-fine-tuning" tabindex="-1">IV-B. LLM Fine-Tuning <a class="header-anchor" href="#iv-b-llm-fine-tuning" aria-label="Permalink to &quot;IV-B. LLM Fine-Tuning&quot;">​</a></h3><p>Fine-tuning the generator improves alignment with retrieved context:</p><ul><li><strong>General Fine-tuning</strong>: Standard supervised fine-tuning on RAG-specific data.</li><li><strong>Distillation from Larger Models</strong>: Train smaller models to mimic larger model RAG behavior.</li><li><strong>Domain-Specific Fine-tuning</strong>: Adapt LLM to specialized domains (medical, legal, code).</li><li><strong>Alignment with Retrieval</strong>: Fine-tune LLM to better utilize retrieved documents (RA-DIT jointly fine-tunes retriever and LLM with KL-divergence alignment).</li><li><strong>Reinforcement Learning</strong>: Use feedback to optimize generation quality in RAG context.</li></ul><hr><h2 id="v-augmentation-in-rag" tabindex="-1">V. Augmentation in RAG <a class="header-anchor" href="#v-augmentation-in-rag" aria-label="Permalink to &quot;V. Augmentation in RAG&quot;">​</a></h2><h3 id="v-a-augmentation-stages" tabindex="-1">V-A. Augmentation Stages <a class="header-anchor" href="#v-a-augmentation-stages" aria-label="Permalink to &quot;V-A. Augmentation Stages&quot;">​</a></h3><p>RAG augmentation can occur at three stages of LLM development:</p><ul><li><strong>Pre-training Stage</strong>: Incorporate retrieval during pre-training (RETRO, Atlas, REALM). Computationally expensive but produces deeply integrated retrieval-enhanced models.</li><li><strong>Fine-tuning Stage</strong>: Augment during fine-tuning process to adapt retrieval behavior to specific tasks.</li><li><strong>Inference Stage</strong>: Most flexible and widely adopted. No model retraining required; retrieval is applied at inference time.</li></ul><h3 id="v-b-augmentation-data-source" tabindex="-1">V-B. Augmentation Data Source <a class="header-anchor" href="#v-b-augmentation-data-source" aria-label="Permalink to &quot;V-B. Augmentation Data Source&quot;">​</a></h3><ul><li><strong>Unstructured data</strong>: Text corpora, Wikipedia, domain-specific collections.</li><li><strong>Structured data</strong>: Knowledge Graphs, databases, tables.</li><li><strong>LLM-generated data</strong>: Self-generated context, hypothetical documents, reasoning chains.</li></ul><h3 id="v-c-augmentation-process" tabindex="-1">V-C. Augmentation Process <a class="header-anchor" href="#v-c-augmentation-process" aria-label="Permalink to &quot;V-C. Augmentation Process&quot;">​</a></h3><ul><li><strong>Once (Single retrieval)</strong>: Retrieve once before generation. Simple but may miss complex multi-hop reasoning.</li><li><strong>Iterative</strong>: Multiple rounds of retrieval and generation (ITER-RETGEN, IRCoT). Better for complex multi-step queries.</li><li><strong>Adaptive</strong>: Decide when and whether to retrieve based on query complexity or confidence (FLARE, Self-RAG). Most efficient approach.</li><li><strong>Recursive</strong>: Hierarchical or tree-structured retrieval and reasoning (ToC, IRCoT).</li></ul><hr><h2 id="vi-rag-evaluation" tabindex="-1">VI. RAG Evaluation <a class="header-anchor" href="#vi-rag-evaluation" aria-label="Permalink to &quot;VI. RAG Evaluation&quot;">​</a></h2><h3 id="vi-a-downstream-tasks-and-datasets" tabindex="-1">VI-A. Downstream Tasks and Datasets <a class="header-anchor" href="#vi-a-downstream-tasks-and-datasets" aria-label="Permalink to &quot;VI-A. Downstream Tasks and Datasets&quot;">​</a></h3><p>RAG is evaluated across 26 downstream tasks including:</p><ul><li>Question Answering (open-domain, multi-hop, conversational)</li><li>Fact Verification</li><li>Commonsense Reasoning</li><li>Information Extraction / Slot Filling</li><li>Dialogue Systems / Task-Oriented Dialogue</li><li>Code Generation</li><li>Summarization</li><li>Machine Translation</li><li>Recommendation</li></ul><p>Key datasets include: Natural Questions, TriviaQA, HotpotQA, 2WikiMultiHopQA, MuSiQue, MS MARCO, FEVER, WoW (Wizard of Wikipedia), and domain-specific datasets.</p><h3 id="vi-b-evaluation-metrics" tabindex="-1">VI-B. Evaluation Metrics <a class="header-anchor" href="#vi-b-evaluation-metrics" aria-label="Permalink to &quot;VI-B. Evaluation Metrics&quot;">​</a></h3><p><strong>Retrieval Quality</strong>:</p><ul><li>Recall@K, Precision@K, MRR (Mean Reciprocal Rank), NDCG (Normalized Discounted Cumulative Gain)</li><li>Context Relevance: measures relevance of retrieved context to the query</li></ul><p><strong>Generation Quality</strong>:</p><ul><li>Faithfulness/Groundedness: whether generated answer is grounded in retrieved context</li><li>Answer Relevance: relevance of answer to original question</li><li>Correctness/Accuracy: factual accuracy</li><li>Fluency and coherence</li><li>ROUGE, BLEU, BERTScore for automated evaluation</li></ul><h3 id="vi-c-evaluation-benchmarks-and-tools" tabindex="-1">VI-C. Evaluation Benchmarks and Tools <a class="header-anchor" href="#vi-c-evaluation-benchmarks-and-tools" aria-label="Permalink to &quot;VI-C. Evaluation Benchmarks and Tools&quot;">​</a></h3><ul><li><strong>RAGAS</strong>: End-to-end RAG evaluation framework measuring faithfulness, answer relevance, context precision, and context recall.</li><li><strong>ARES</strong>: Automated RAG Evaluation System using LLM-as-judge approach.</li><li><strong>TruLens</strong>: Evaluation framework focusing on groundedness and relevance.</li><li><strong>RGB (RAG Benchmark)</strong>: Tests RAG systems on noise robustness, negative rejection, information integration, and counterfactual robustness.</li><li><strong>RECALL</strong>: Evaluates counterfactual robustness.</li></ul><hr><h2 id="vii-challenges-and-future-directions" tabindex="-1">VII. Challenges and Future Directions <a class="header-anchor" href="#vii-challenges-and-future-directions" aria-label="Permalink to &quot;VII. Challenges and Future Directions&quot;">​</a></h2><h3 id="current-challenges" tabindex="-1">Current Challenges <a class="header-anchor" href="#current-challenges" aria-label="Permalink to &quot;Current Challenges&quot;">​</a></h3><p><strong>Retrieval Quality</strong>:</p><ul><li>Long-context retrieval and processing</li><li>Multi-modal retrieval (text + images + tables)</li><li>Handling conflicting or noisy retrieved information</li><li>Retrieval latency in production settings</li></ul><p><strong>Generation Quality</strong>:</p><ul><li>Balancing retrieved context with parametric knowledge</li><li>Avoiding &quot;lost in the middle&quot; problem with long contexts</li><li>Mitigating hallucination when retrieved context is incomplete or wrong</li></ul><p><strong>Augmentation</strong>:</p><ul><li>Determining optimal retrieval frequency (when to retrieve)</li><li>Multi-hop and cross-document reasoning</li><li>Maintaining coherence across iterative retrieval steps</li></ul><p><strong>System-Level</strong>:</p><ul><li>Lack of standardized evaluation benchmarks</li><li>RAG robustness to noisy or adversarial retrieval results</li><li>Efficiency and scalability in production</li><li>Extending RAG beyond text to multi-modal settings</li></ul><h3 id="future-directions" tabindex="-1">Future Directions <a class="header-anchor" href="#future-directions" aria-label="Permalink to &quot;Future Directions&quot;">​</a></h3><ol><li><strong>Long Context RAG</strong>: Adapt to ever-increasing context windows while maintaining efficiency.</li><li><strong>Multi-Modal RAG</strong>: Extend retrieval to images, audio, video, and structured data.</li><li><strong>RAG + Agent</strong>: Integration with autonomous agents for multi-step, tool-using RAG.</li><li><strong>Knowledge Graph + RAG</strong>: Deeper integration for more structured and verifiable retrieval.</li><li><strong>Adaptive and On-Demand RAG</strong>: More sophisticated policies for when and how much to retrieve.</li><li><strong>RAG for Domain-Specific Applications</strong>: Medical, legal, scientific, and enterprise settings.</li><li><strong>Scalable Evaluation</strong>: Better automated evaluation frameworks that correlate with human judgment.</li><li><strong>Privacy-Preserving RAG</strong>: Ensuring sensitive information in external databases is protected.</li></ol><hr><h2 id="summary-of-rag-methods-selected-from-table-i" tabindex="-1">Summary of RAG Methods (Selected from Table I) <a class="header-anchor" href="#summary-of-rag-methods-selected-from-table-i" aria-label="Permalink to &quot;Summary of RAG Methods (Selected from Table I)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Method</th><th>Retrieval Source</th><th>Data Type</th><th>Granularity</th><th>Aug. Stage</th><th>Retrieval Process</th></tr></thead><tbody><tr><td>CoG</td><td>Wikipedia</td><td>Text</td><td>Phrase</td><td>Pre-training</td><td>Iterative</td></tr><tr><td>DenseX</td><td>FactoidWiki</td><td>Text</td><td>Proposition</td><td>Inference</td><td>Once</td></tr><tr><td>Self-Mem</td><td>Dataset-base</td><td>Text</td><td>Sentence</td><td>Tuning</td><td>Iterative</td></tr><tr><td>FLARE</td><td>Search Engine, Wikipedia</td><td>Text</td><td>Sentence</td><td>Tuning</td><td>Adaptive</td></tr><tr><td>Atlas</td><td>Wikipedia, Common Crawl</td><td>Text</td><td>Chunk</td><td>Pre-training</td><td>Iterative</td></tr><tr><td>RETRO++</td><td>Pre-training Corpus</td><td>Text</td><td>Chunk</td><td>Pre-training</td><td>Iterative</td></tr><tr><td>Self-RAG</td><td>Wikipedia</td><td>Text</td><td>Chunk</td><td>Tuning</td><td>Adaptive</td></tr><tr><td>ITER-RETGEN</td><td>Wikipedia</td><td>Text</td><td>Chunk</td><td>Inference</td><td>Iterative</td></tr><tr><td>IRCoT</td><td>Wikipedia</td><td>Text</td><td>Chunk</td><td>Inference</td><td>Recursive</td></tr><tr><td>RAPTOR</td><td>Dataset-base</td><td>Text</td><td>Chunk</td><td>Inference</td><td>Recursive</td></tr><tr><td>DSP</td><td>Wikipedia</td><td>Text</td><td>Doc</td><td>Inference</td><td>Iterative</td></tr><tr><td>HyDE</td><td>Various</td><td>Text</td><td>Doc</td><td>Inference</td><td>Once</td></tr><tr><td>SURGE</td><td>Freebase</td><td>KG</td><td>Sub-Graph</td><td>Tuning</td><td>Once</td></tr><tr><td>KnowledGPT</td><td>Dataset-base</td><td>KG</td><td>Triplet</td><td>Inference</td><td>Multi-time</td></tr><tr><td>RoG</td><td>Freebase</td><td>KG</td><td>Triplet</td><td>Inference</td><td>Iterative</td></tr><tr><td>G-Retriever</td><td>Dataset-base</td><td>TextGraph</td><td>Sub-Graph</td><td>Inference</td><td>Once</td></tr></tbody></table><hr><h2 id="key-references" tabindex="-1">Key References <a class="header-anchor" href="#key-references" aria-label="Permalink to &quot;Key References&quot;">​</a></h2><ol><li>Lewis et al. (2020). Retrieval-Augmented Generation for Knowledge-Intensive NLP Tasks. NeurIPS. (Foundational RAG paper)</li><li>Guu et al. (2020). REALM: Retrieval-Augmented Language Model Pre-Training. ICML.</li><li>Borgeaud et al. (2022). Improving Language Models by Retrieving from Trillions of Tokens (RETRO). ICML.</li><li>Izacard &amp; Grave (2021). Leveraging Passage Retrieval with Generative Models for Open Domain Question Answering (FiD). EACL.</li><li>Asai et al. (2023). Self-RAG: Learning to Retrieve, Generate, and Critique through Self-Reflection.</li><li>Jiang et al. (2023). Active Retrieval Augmented Generation (FLARE).</li><li>Ma et al. (2023). Query Rewriting for Retrieval-Augmented Large Language Models (RRR).</li><li>Shi et al. (2023). REPLUG: Retrieval-Augmented Black-Box Language Models.</li><li>Khattab et al. (2022). Demonstrate-Search-Predict (DSP).</li><li>Gao et al. (2022). Precise Zero-Shot Dense Retrieval without Relevance Labels (HyDE).</li><li>Zheng et al. (2023). Step-Back Prompting.</li><li>Trivedi et al. (2022). Interleaving Retrieval with Chain-of-Thought Reasoning (IRCoT).</li><li>Yu et al. (2023). Generate rather than Retrieve (GenRead).</li><li>Shao et al. (2023). Enhancing Retrieval-Augmented Large Language Models with Iterative Retrieval-Generation (ITER-RETGEN).</li><li>Ram et al. (2023). In-Context Retrieval-Augmented Language Models (ICRALM).</li><li>Es et al. (2023). RAGAS: Automated Evaluation of Retrieval Augmented Generation.</li><li>GitHub repository: <a href="https://github.com/Tongji-KGLLM/RAG-Survey" target="_blank" rel="noreferrer">https://github.com/Tongji-KGLLM/RAG-Survey</a></li></ol>',111)])])}const m=t(r,[["render",o]]);export{h as __pageData,m as default};
